// VALID JSON
{
  "name": "John",
  "age": 30,
  "hobbies": ["reading", "gaming"],
  "isActive": true
}

// INVALID JSON (note the issues)
{
  "name": "John",
  "age": 30,
  'hobbies': ['reading', 'gaming'],  // Single quotes not allowed
  "isActive": true,                  // Trailing comma
}

// JavaScript examples

// Parsing JSON string to object
const jsonString = '{"name": "Alice", "age": 28}';
const obj = JSON.parse(jsonString);
console.log(obj.name);  // "Alice"

// Stringifying object to JSON string
const person = {name: "Bob", age: 30};
const json = JSON.stringify(person);
console.log(json);  // '{"name":"Bob","age":30}'
